/**
 * Confirm service — atomically writes confirmed modules/tasks to DB
 * and activates the milestone (draft → in-progress).
 *
 * Pre-generates all IDs, then uses a synchronous drizzle transaction
 * (required by better-sqlite3) for atomic writes.
 */

import { eq } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, tasks, milestones } from '$lib/db/schema.js';
import type { ConfirmModule } from '$lib/schemas/confirm.js';

// ── Types ────────────────────────────────────────────────────────────────────

export interface ConfirmResultModule {
	id: string;
	milestoneId: string;
	name: string;
	description: string | null;
	status: string;
	sortOrder: number;
	tasks: ConfirmResultTask[];
}

export interface ConfirmResultTask {
	id: string;
	shortId: number;
	moduleId: string;
	title: string;
	description: string | null;
	status: string;
}

export interface ConfirmError {
	code: 'not_found' | 'bad_request';
	message: string;
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Confirm a milestone's decomposed modules and tasks.
 *
 * - Validates milestone exists, is 'draft', and has sourceMd
 * - Pre-generates all IDs (async phase)
 * - Inserts all modules and tasks in a synchronous transaction
 * - Updates milestone status to 'in-progress'
 * - Returns the created structure with all generated IDs
 */
export async function confirmMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	confirmedModules: ConfirmModule[]
): Promise<{ data: ConfirmResultModule[] } | { error: ConfirmError }> {
	// 1. Validate milestone preconditions (outside transaction — read-only)
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, milestoneId))
		.get();

	if (!milestone) {
		return { error: { code: 'not_found', message: `Milestone ${milestoneId} not found` } };
	}

	if (milestone.status !== 'draft') {
		return {
			error: {
				code: 'bad_request',
				message: `Milestone status is '${milestone.status}', expected 'draft'`
			}
		};
	}

	if (!milestone.sourceMd) {
		return {
			error: {
				code: 'bad_request',
				message: 'Milestone has no source markdown'
			}
		};
	}

	// 2. Pre-generate all IDs (async — must happen before sync transaction)
	// We scan once for the current max, then increment in memory.
	const existingModules = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();

	let maxModuleSeq = 0;
	for (const row of existingModules) {
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxModuleSeq) maxModuleSeq = seq;
	}

	const existingTasks = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxTaskSeq = 0;
	let maxShortId = 0;
	for (const row of existingTasks) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxTaskSeq) maxTaskSeq = seq;
		if (row.shortId > maxShortId) maxShortId = row.shortId;
	}

	// Build module entries with pre-computed IDs
	const moduleEntries: Array<{
		id: string;
		mod: ConfirmModule;
		index: number;
	}> = [];

	for (let i = 0; i < confirmedModules.length; i++) {
		maxModuleSeq++;
		moduleEntries.push({
			id: `MOD-${milestoneId.replace('MS-', '')}-${maxModuleSeq}`,
			mod: confirmedModules[i],
			index: i
		});
	}

	// Build task entries with pre-computed IDs
	const taskEntries: Array<{
		id: string;
		shortId: number;
		moduleIndex: number;
		taskIndex: number;
		title: string;
		description: string | null;
	}> = [];

	for (const entry of moduleEntries) {
		for (let t = 0; t < entry.mod.tasks.length; t++) {
			maxTaskSeq++;
			maxShortId++;
			taskEntries.push({
				id: `TASK-${maxTaskSeq}`,
				shortId: maxShortId,
				moduleIndex: entry.index,
				taskIndex: t,
				title: entry.mod.tasks[t].title,
				description: entry.mod.tasks[t].description ?? null
			});
		}
	}

	// 3. Atomic write in a synchronous transaction
	const createdModules = db.transaction((tx) => {
		const result: ConfirmResultModule[] = [];

		for (const entry of moduleEntries) {
			tx.insert(modules).values({
				id: entry.id,
				milestoneId,
				name: entry.mod.name,
				description: entry.mod.description ?? null,
				sortOrder: entry.index
			}).run();

			const modTasks = taskEntries
				.filter((te) => te.moduleIndex === entry.index)
				.map((te) => {
					tx.insert(tasks).values({
						id: te.id,
						shortId: te.shortId,
						moduleId: entry.id,
						title: te.title,
						description: te.description
					}).run();

					return {
						id: te.id,
						shortId: te.shortId,
						moduleId: entry.id,
						title: te.title,
						description: te.description,
						status: 'todo'
					};
				});

			result.push({
				id: entry.id,
				milestoneId,
				name: entry.mod.name,
				description: entry.mod.description ?? null,
				status: 'draft',
				sortOrder: entry.index,
				tasks: modTasks
			});
		}

		// Activate milestone
		tx.update(milestones)
			.set({ status: 'in-progress' })
			.where(eq(milestones.id, milestoneId))
			.run();

		return result;
	});

	const totalTasks = createdModules.reduce((sum, m) => sum + m.tasks.length, 0);
	console.info('[confirm-service] Milestone confirmed:', {
		milestoneId,
		moduleCount: createdModules.length,
		taskCount: totalTasks
	});

	return { data: createdModules };
}

/**
 * Compare service — streams LLM comparison of decomposed result vs original requirements.
 *
 * Takes source markdown + confirmed modules/tasks, asks the LLM to compare
 * and suggest improvements. Output is advisory plain text (not structured JSON).
 *
 * Uses SSE events: suggestion (text chunks), done, error.
 */

import { LlmClient } from './llm-client.js';
import type { ConfirmModule } from '$lib/schemas/confirm.js';
import type {
	CompareEvent,
	CompareSuggestionEvent,
	CompareErrorEvent,
	CompareDoneEvent
} from '$lib/schemas/confirm.js';

// ── System prompt ────────────────────────────────────────────────────────────

const SYSTEM_PROMPT = `你是一个专业的项目管理助手。你的任务是对比原始需求文档和拆解结果，给出改进建议。

## 工作方式

1. 仔细阅读原始需求文档
2. 对比已拆解的模块和任务
3. 指出可能遗漏的需求点
4. 建议模块或任务的优化方向
5. 标注优先级较高的建议

## 输出要求

- 用简洁的中文输出分析结果
- 每个建议单独一段，标注类型（遗漏/优化/拆分建议）
- 最后给出一个简短的总结评分（覆盖度 0-100%）
- 不要输出 JSON 或结构化格式，直接输出纯文本`;

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Stream LLM comparison of source markdown vs confirmed modules.
 *
 * Yields CompareEvent objects:
 * - `{ type: 'suggestion', content }` — text chunk from LLM
 * - `{ type: 'error', stage, message }` — error during streaming
 * - `{ type: 'done' }` — stream complete
 */
export async function* streamCompare(
	sourceMd: string,
	confirmedModules: ConfirmModule[],
	client?: LlmClient
): AsyncGenerator<CompareEvent> {
	const llm = client ?? new LlmClient();

	// Build a structured text representation of the confirmed modules
	const modulesText = confirmedModules
		.map((mod, idx) => {
			const tasksText = mod.tasks.map((t, tIdx) => `    ${tIdx + 1}. ${t.title}${t.description ? ` - ${t.description}` : ''}`).join('\n');
			return `模块 ${idx + 1}: ${mod.name}${mod.description ? `\n  描述: ${mod.description}` : ''}\n  任务:\n${tasksText}`;
		})
		.join('\n\n');

	const userMessage = `## 原始需求文档

${sourceMd}

## 拆解结果

${modulesText}

请对比以上内容，给出改进建议。`;

	console.info('[compare-service] Starting comparison:', {
		sourceMdLength: sourceMd.length,
		moduleCount: confirmedModules.length,
		taskCount: confirmedModules.reduce((sum, m) => sum + m.tasks.length, 0)
		// apiKey intentionally omitted
	});

	try {
		for await (const chunk of llm.chatCompletionStream(SYSTEM_PROMPT, userMessage)) {
			const event: CompareSuggestionEvent = {
				type: 'suggestion',
				content: chunk
			};
			yield event;
		}

		const doneEvent: CompareDoneEvent = { type: 'done' };
		yield doneEvent;
		console.info('[compare-service] Comparison complete');
	} catch (err: any) {
		const stage: 'connecting' | 'streaming' = 'connecting';
		const errorEvent: CompareErrorEvent = {
			type: 'error',
			stage,
			message: err.message
		};
		yield errorEvent;
		console.info('[compare-service] Stream error:', err.message);
	}
}

/**
 * POST /api/milestones/:id/confirm
 *
 * Confirms a milestone's decomposed modules and tasks.
 * Validates body with confirmRequestSchema, calls confirmService,
 * returns JSON with created module/task IDs.
 */

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';
import { confirmMilestone } from '$lib/server/confirm-service.js';
import { confirmRequestSchema } from '$lib/schemas/confirm.js';

// ── Handler ──────────────────────────────────────────────────────────────────

export const POST: RequestHandler = async ({ params, request }) => {
	// Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json(
			{ error: { code: 'bad_request', message: 'Invalid JSON body' } },
			{ status: 400 }
		);
	}

	const parsed = confirmRequestSchema.safeParse(body);
	if (!parsed.success) {
		const details = parsed.error.issues.map((i) => ({
			field: i.path.join('.'),
			message: i.message
		}));
		return json(
			{ error: { code: 'validation_error', message: 'Request validation failed', details } },
			{ status: 400 }
		);
	}

	// Check milestone exists
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		return json(
			{ error: { code: 'not_found', message: `Milestone ${params.id} not found` } },
			{ status: 404 }
		);
	}

	// Check status is draft
	if (milestone.status !== 'draft') {
		return json(
			{ error: { code: 'bad_request', message: `Milestone status is '${milestone.status}', expected 'draft'` } },
			{ status: 400 }
		);
	}

	// Execute confirm
	const result = await confirmMilestone(db, params.id, parsed.data.modules);

	if ('error' in result) {
		const status = result.error.code === 'not_found' ? 404 : 400;
		return json({ error: result.error }, { status });
	}

	return json({
		milestoneId: params.id,
		modules: result.data
	});
};

/**
 * POST /api/milestones/:id/compare
 *
 * Streams LLM comparison of source markdown vs confirmed modules as SSE.
 * Validates milestone exists, then streams CompareEvents.
 */

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';
import { streamCompare } from '$lib/server/compare-service.js';
import { compareRequestSchema } from '$lib/schemas/confirm.js';
import type { CompareEvent } from '$lib/schemas/confirm.js';

// ── SSE formatting helpers ──────────────────────────────────────────────────

function formatSSE(event: CompareEvent): string {
	return `event: ${event.type}\ndata: ${JSON.stringify(event)}\n\n`;
}

// ── Handler ──────────────────────────────────────────────────────────────────

export const POST: RequestHandler = async ({ params, request }) => {
	// Check milestone exists
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		return json(
			{ error: { code: 'not_found', message: `Milestone ${params.id} not found` } },
			{ status: 404 }
		);
	}

	// Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json(
			{ error: { code: 'bad_request', message: 'Invalid JSON body' } },
			{ status: 400 }
		);
	}

	const parsed = compareRequestSchema.safeParse(body);
	if (!parsed.success) {
		const details = parsed.error.issues.map((i) => ({
			field: i.path.join('.'),
			message: i.message
		}));
		return json(
			{ error: { code: 'validation_error', message: 'Request validation failed', details } },
			{ status: 400 }
		);
	}

	const sourceMd = milestone.sourceMd ?? '';

	// Stream SSE events from the compare service
	const generator = streamCompare(sourceMd, parsed.data.modules);

	const stream = new ReadableStream({
		async start(controller) {
			const encoder = new TextEncoder();
			try {
				for await (const event of generator) {
					controller.enqueue(encoder.encode(formatSSE(event)));
				}
				controller.close();
			} catch (err: any) {
				try {
					const errorEvent: CompareEvent = {
						type: 'error',
						stage: 'streaming',
						message: err.message
					};
					controller.enqueue(encoder.encode(formatSSE(errorEvent)));
					controller.close();
				} catch {
					// Controller already closed
				}
			}
		}
	});

	return new Response(stream, {
		headers: {
			'Content-Type': 'text/event-stream',
			'Cache-Control': 'no-cache',
			'Connection': 'keep-alive'
		}
	});
};

/**
 * Shared client-side state for decompose preview/edit flow.
 *
 * Stores pending decompose modules keyed by milestoneId so that
 * DecomposeStream → stores results → preview page reads them.
 *
 * Uses Svelte 5 runes for reactivity.
 */

import type { DecomposeModule } from '$lib/schemas/decompose.js';

// ── Types ────────────────────────────────────────────────────────────────────

/** Editable module with checked state for confirm selection. */
export interface EditableModule {
	name: string;
	description: string;
	checked: boolean;
	tasks: EditableTask[];
}

/** Editable task with checked state. */
export interface EditableTask {
	title: string;
	description: string;
	checked: boolean;
}

// ── State ────────────────────────────────────────────────────────────────────

const pendingMap = $state<Record<string, EditableModule[]>>({});

// ── Public API ───────────────────────────────────────────────────────────────

/** Store pending modules for a milestone. Converts DecomposeModule[] → EditableModule[]. */
export function setPendingModules(milestoneId: string, modules: DecomposeModule[]): void {
	pendingMap[milestoneId] = modules.map((m) => ({
		name: m.name,
		description: m.description ?? '',
		checked: true,
		tasks: m.tasks.map((t) => ({
			title: t.title,
			description: t.description ?? '',
			checked: true
		}))
	}));
}

/** Get pending modules for a milestone (or null if none stored). */
export function getPendingModules(milestoneId: string): EditableModule[] | null {
	return pendingMap[milestoneId] ?? null;
}

/** Clear pending modules for a milestone (e.g. after confirm). */
export function clearPendingModules(milestoneId: string): void {
	delete pendingMap[milestoneId];
}

/** Check whether a milestone has pending modules in the store. */
export function hasPendingModules(milestoneId: string): boolean {
	return (pendingMap[milestoneId]?.length ?? 0) > 0;
}

